for (uint256 i = 0; i < _tokenAddresses.length; ++i) {
    (, uint256 ltv,,,,,,,,) = dataProvider.getReserveConfigurationData(_tokenAddresses[i]);
    (address aToken,,) = dataProvider.getReserveTokensAddresses(_tokenAddresses[i]);
    if (_tokenAddresses[i] == 0x408e41876cCCDC0F92210600ef50372656052a38) {
        tokens[i] = TokenInfo({
            aTokenAddress: aToken,
            underlyingTokenAddress: _tokenAddresses[i],
            collateralFactor: ltv,
            price: 1_977_943_724_421
        });
    } else {
        tokens[i] = TokenInfo({
            aTokenAddress: aToken,
            underlyingTokenAddress: _tokenAddresses[i],
            collateralFactor: ltv,
            price: IPriceOracleGetterAave(priceOracleAddress)
                .getAssetPrice(_tokenAddresses[i])
        });
    }
}

if (srcRep != dstRep && amount > 0) {
    if (srcRep != address(0)) {
        uint32 srcRepNum = numCheckpoints[srcRep];
        uint96 srcRepOld = srcRepNum > 0 ? checkpoints[srcRep][srcRepNum - 1].votes : 0;
        uint96 srcRepNew = sub96(srcRepOld, amount, "Comp::_moveVotes: vote amount underflows");
        _writeCheckpoint(srcRep, srcRepNum, srcRepOld, srcRepNew);
    }

    if (dstRep != address(0)) {
        uint32 dstRepNum = numCheckpoints[dstRep];
        uint96 dstRepOld = dstRepNum > 0 ? checkpoints[dstRep][dstRepNum - 1].votes : 0;
        uint96 dstRepNew = add96(dstRepOld, amount, "Comp::_moveVotes: vote amount overflows");
        _writeCheckpoint(dstRep, dstRepNum, dstRepOld, dstRepNew);
    }
}

assembly {
    mstore(0x20, tree.slot)
    mstore(0x00, _NODES_SLOT_SEED)
    nodes := shl(_NODES_SLOT_SHIFT, keccak256(0x00, 0x40))
    // Layout scratch space so that `mload(0x00) == 0`, `mload(0x01) == _BITPOS_RIGHT`.
    mstore(0x01, _BITPOS_RIGHT) // `_BITPOS_RIGHT` is 31.
    for { let probe := shr(128, sload(nodes)) } probe {} {
        cursor := probe
        let nodePacked := sload(or(nodes, probe))
        let nodeValue := shr(_BITPOS_PACKED_VALUE, nodePacked)
        if iszero(nodeValue) {
            nodeValue := sload(or(or(nodes, probe), _BIT_FULL_VALUE_SLOT))
        }
        if eq(nodeValue, x) {
            key := cursor
            break
        }
        probe := and(shr(mload(gt(x, nodeValue)), nodePacked), _BITMASK_KEY)
    }
}
